ValidationRule.errorConditionFormula:
/* BLOCKIERT: Änderung der Account-Verknüpfung (AccountId). ERLAUBT FÜR: Genehmigungsprozesse, spezifische Profile, definierte Power-User & Custom Permission. */
ISCHANGED(AccountId) && In_Genehmigungsprozess__c == false && NOT($Permission.ChangeContactAccount) &&
/* --- PROFIL AUSNAHMEN (Empfehlung: IDs durch Namen ersetzen) --- */ $User.ProfileId != '00eb00000015urz' && $User.ProfileId != '00e0X000001A72a' && $User.ProfileId != '00e0X000000ds1P' &&
/* --- AKTIVE POWER-USER (Ausnahmen laut Export) --- */ $User.Id != '005b00000029D0o' && /* Anika Krüger */ $User.Id != '005b0000001V30P' && /* System (Witte) */ $User.Id != '005b0000000YQy4' && /* Harald Senftleben */ $User.Id != '005Vi00000hPk25' /* Peter Schröder */
